exploreUrl:
@js:
var result = [];
var push = function(title, url, size) {
  result.push({
    title: title,
    url: url,
    style: {
      layout_flexGrow: 1,
      layout_flexBasisPercent: size
    }
  });
};

var cats = [
  ['玄幻魔法', '/novels/class/1_{{page}}.html'],
  ['武侠修真', '/novels/class/2_{{page}}.html'],
  ['都市言情', '/novels/class/3_{{page}}.html'],
  ['历史军事', '/novels/class/4_{{page}}.html'],
  ['科幻灵异', '/novels/class/6_{{page}}.html'],
  ['游戏竞技', '/novels/class/5_{{page}}.html'],
  ['女生耽美', '/novels/class/7_{{page}}.html'],
  ['其他类型', '/novels/class/8_{{page}}.html']
];
cats.forEach(function(c) { push(c[0], c[1], 0.25); });

JSON.stringify(result);
